+#define C10_THROW_ERROR_FORMATTED(ErrorType, ...) \
+  do {                                            \
+    std::ostringstream oss;                       \
+    oss << __VA_ARGS__;                           \
+    C10_THROW_ERROR(ErrorType, oss.str());        \
+  } while (0)
+
+namespace torch_ext {
+
+namespace common = tensorrt_llm::common;
+namespace kernels = tensorrt_llm::kernels;
+using profiler_backend = kernels::GemmProfilerBackend;
+
+class FusedMoeRunner : public torch::CustomClassHolder {
+ public:
+  template <typename Type, bool NeedQuant = false>
+  std::unique_ptr<kernels::CutlassMoeFCRunnerInterface> switch_output_type(
+      c10::ScalarType output_type) {
+    switch (output_type) {
+      case c10::ScalarType::Long:  // INT64 == FP4
+      case c10::ScalarType::Float8_e4m3fn:
+        // TODO We need an atomic FP8 reduction for the finalize fusions
+        C10_THROW_ERROR_FORMATTED(NotImplementedError,
+                                  "Outputting " << torch::toString(output_type)
+                                                << " directly is not currently supported");
+        // return std::make_unique<kernels::CutlassMoeFCRunner<Type, Type>>();
+      case c10::ScalarType::Half:
+        if constexpr (NeedQuant) {
+          return std::make_unique<kernels::CutlassMoeFCRunner<Type, Type, half, half>>();
+        } else {
+          return std::make_unique<kernels::CutlassMoeFCRunner<Type, Type, half, Type>>();
+        }
+#ifdef ENABLE_BF16
+      case c10::ScalarType::BFloat16:
+        if constexpr (NeedQuant) {
+          return std::make_unique<
+              kernels::CutlassMoeFCRunner<Type, Type, __nv_bfloat16, __nv_bfloat16>>();
+        } else {
+          return std::make_unique<kernels::CutlassMoeFCRunner<Type, Type, __nv_bfloat16, Type>>();
+        }
+#endif
+      default:
+        C10_THROW_ERROR_FORMATTED(Error, "Invalid output type "
+                                             << torch::toString(output_type) << " specified for "
+                                             << torch::toString(mActivationDtype));
+    }
+  };
+
+  FusedMoeRunner(c10::ScalarType activation_dtype, c10::ScalarType weight_dtype,
+                 c10::ScalarType output_dtype, bool use_fp8_block_scaling,
+                 bool use_w4a8_group_scaling) {
+    mActivationDtype = activation_dtype;
+    mWeightDtype = weight_dtype;
+    mOutputDtype = output_dtype;
+    mUseFp8BlockScaling = use_fp8_block_scaling;
+    mUseW4A8GroupScaling = use_w4a8_group_scaling;
+    mInnerDimMultiplier = 1;
+
+    // keep consistent with cpp/tensorrt_llm/plugins/mixtureOfExperts/mixtureOfExpertsPlugin.cpp
+    if (mActivationDtype == c10::ScalarType::Half && mWeightDtype == c10::ScalarType::Half) {
+      mKernelRunner = std::make_shared<kernels::CutlassMoeFCRunner<half, half>>();
+    }
+#ifdef ENABLE_BF16
+    else if (mActivationDtype == c10::ScalarType::BFloat16 &&
+             mWeightDtype == c10::ScalarType::BFloat16) {
+      mKernelRunner = std::make_shared<kernels::CutlassMoeFCRunner<__nv_bfloat16, __nv_bfloat16>>();
+    }
+#ifdef ENABLE_FP8
+    else if (mActivationDtype == c10::ScalarType::BFloat16 &&
+             mWeightDtype == c10::ScalarType::Float8_e4m3fn) {
+      mKernelRunner = std::make_unique<kernels::CutlassMoeFCRunner<__nv_bfloat16, __nv_fp8_e4m3>>();
+    }
+#endif
+#endif
+
+#ifdef ENABLE_FP8
+    if (isFp8Quant()) {
+      mKernelRunner = switch_output_type<__nv_fp8_e4m3>(mOutputDtype);
+    }
+#endif
+#ifdef ENABLE_FP4
+    if (isNvfp4Quant()) {
+      mInnerDimMultiplier = 16;
+      switch (mActivationDtype) {
+        case c10::ScalarType::Half:
+#ifdef ENABLE_BF16
+        case c10::ScalarType::BFloat16:
+#endif
+          mKernelRunner = switch_output_type<__nv_fp4_e2m1, true>(mOutputDtype);
+          break;
+        default:
+          mKernelRunner = switch_output_type<__nv_fp4_e2m1, false>(mOutputDtype);
+      }
+    }
+#endif
+    if (isInt4Quant()) {
+      mInnerDimMultiplier = 2;
+      if (mActivationDtype == c10::ScalarType::Half) {
+#ifdef ENABLE_FP8
+        if (mUseW4A8GroupScaling) {
+          mKernelRunner = std::make_unique<
+              kernels::CutlassMoeFCRunner<__nv_fp8_e4m3, cutlass::uint4b_t, half, half>>();
+        } else {
+          mKernelRunner = std::make_shared<kernels::CutlassMoeFCRunner<half, cutlass::uint4b_t>>();
+        }
+#else
+        mKernelRunner = std::make_shared<kernels::CutlassMoeFCRunner<half, cutlass::uint4b_t>>();
+#endif
+      }
+#ifdef ENABLE_BF16
+      else if (mActivationDtype == c10::ScalarType::BFloat16) {
+#ifdef ENABLE_FP8
+        if (mUseW4A8GroupScaling) {
+          mKernelRunner =
+              std::make_unique<kernels::CutlassMoeFCRunner<__nv_fp8_e4m3, cutlass::uint4b_t,
+                                                           __nv_bfloat16, __nv_bfloat16>>();
+        } else {
+          mKernelRunner =
+              std::make_shared<kernels::CutlassMoeFCRunner<__nv_bfloat16, cutlass::uint4b_t>>();
+        }
+#else
+        mKernelRunner =
+            std::make_shared<kernels::CutlassMoeFCRunner<__nv_bfloat16, cutlass::uint4b_t>>();
+#endif
+      }
+#endif
+    }
+    if (!mKernelRunner) {
+      C10_THROW_ERROR_FORMATTED(
+          Error,
+          "Could not construct fused moe op with the requested input combination Activation: "
+              << torch::toString(mActivationDtype) << ", Weight: " << torch::toString(mWeightDtype)
+              << ", Output: " << torch::toString(mOutputDtype));
+    }
+
+    mProfiler = std::make_shared<kernels::GemmProfilerBackend>();
+    mAllProfiles = mKernelRunner->getTactics();
+  }
+
+  ~FusedMoeRunner() {
+    if (mProfileWorkspace != nullptr) {
+      auto const cu_free_status = cudaFree(mProfileWorkspace);
+      TORCH_CHECK(cu_free_status == cudaSuccess,
+                  "Can't free profile workspace during FusedMoeRunner destruction.");
+    }
+  }
+
+  FusedMoeRunner(FusedMoeRunner const&) = delete;
+  void operator=(FusedMoeRunner const&) = delete;
+
+  at::Tensor runMoe(at::Tensor const& input, at::Tensor const& token_selected_experts,
+                    std::optional<at::Tensor> token_final_scales,
+                    at::Tensor const& fc1_expert_weights, at::Tensor const& fc2_expert_weights,
+                    std::optional<c10::ArrayRef<at::Tensor>> quant_scales,
+                    std::optional<at::Tensor> input_sf, int64_t const tp_size,
+                    int64_t const tp_rank, int64_t const ep_size, int64_t const ep_rank,
+                    int64_t const cluster_size, int64_t const cluster_rank, bool min_latency_mode,
+                    std::optional<c10::ArrayRef<int64_t>> profile_ids) {
+    std::lock_guard<std::mutex> lock(mMutex);
+
+    // Free the profile workspace to save memory
+    freeProfileWorkspace();
+
+    TORCH_CHECK(cluster_size == 1 && cluster_rank == 0,
+                "smart_router is supported in min_latency mode");
+
+    CHECK_INPUT_TYPE(input, mActivationDtype)
+    CHECK_INPUT_TYPE(token_selected_experts, at::ScalarType::Int)
+    if (token_final_scales) {
+      CHECK_INPUT_TYPE(token_final_scales.value(), at::ScalarType::Float)
+    }
+    CHECK_INPUT_TYPE(fc1_expert_weights, mWeightDtype)
+    CHECK_INPUT_TYPE(fc2_expert_weights, mWeightDtype)
+
+    TORCH_CHECK(input.dim() == 2, "input must be 2D.");
+    TORCH_CHECK(token_selected_experts.dim() == 2, "token_selected_experts must be 2D.");
+
+    TORCH_CHECK(fc1_expert_weights.dim() == 3, "fc1_expert_weights must be 3D.");
+    TORCH_CHECK(fc2_expert_weights.dim() == 3, "fc2_expert_weights must be 3D.");
+    TORCH_CHECK(input.sizes()[0] == token_selected_experts.sizes()[0],
+                "input and token_selected_experts must have the same num tokens.");
+    if (token_final_scales) {
+      TORCH_CHECK(token_final_scales.value().dim() == 2,
+                  "token_selected_experts_probs must be 2D.");
+      TORCH_CHECK(input.sizes()[0] == token_final_scales.value().sizes()[0],
+                  "input and token_selected_experts_probs must have the same num tokens.");
+      TORCH_CHECK(token_selected_experts.sizes()[1] == token_final_scales.value().sizes()[1],
+                  "token_selected_experts and token_final_scales must have the same number of "
+                  "experts per token.");
+    }
+    TORCH_CHECK(fc1_expert_weights.sizes()[0] == fc2_expert_weights.sizes()[0],
+                "fc1_expert_weights and fc2_expert_weights must have the same number of experts.");
+    TORCH_CHECK(
+        fc1_expert_weights.sizes()[1] == fc2_expert_weights.sizes()[2] * mInnerDimMultiplier * 2,
+        "fc1_expert_weights inter size must be 2 times fc2_expert_weights inter size.");
+
+    int experts_per_token = token_selected_experts.sizes()[1];
+    int64_t num_rows = input.sizes()[0];
+    int64_t hidden_size = fc2_expert_weights.sizes()[1];
+    int64_t inter_size = fc2_expert_weights.sizes()[2] * mInnerDimMultiplier;
+    int const num_experts_on_rank = fc2_expert_weights.sizes()[0];
+    auto const num_experts_total = static_cast<int>(num_experts_on_rank * ep_size);
+    auto parallelism_config = kernels::MOEParallelismConfig(tp_size, tp_rank, ep_size, ep_rank);
+    auto activation_type = tensorrt_llm::ActivationType::Swiglu;
+
+    setRunnerProfiles(profile_ids);
+
+    auto stream = at::cuda::getCurrentCUDAStream(input.get_device());
+
+    std::vector<int64_t> output_shape = {num_rows, hidden_size};
+    auto output = torch::empty(output_shape, input.options().dtype(mOutputDtype));
+
+    WorkspaceInfo workspace_info = getWorkspaceInfo(
+        num_rows, hidden_size, inter_size, num_experts_total, static_cast<int>(experts_per_token),
+        activation_type, parallelism_config, min_latency_mode);
+
+    auto const quant_params =
+        getQuantParams(num_experts_on_rank, hidden_size, inter_size, quant_scales);
+    kernels::MoeMinLatencyParams min_latency_params{};
+
+    // TODO: support lora in the future
+    kernels::LoraParams lora_params{};
+    mKernelRunner->runMoe(
+        input.const_data_ptr(), input_sf.has_value() ? input_sf.value().const_data_ptr() : nullptr,
+        reinterpret_cast<int const*>(token_selected_experts.const_data_ptr()),
+        token_final_scales.has_value()
+            ? reinterpret_cast<float const*>(token_final_scales.value().const_data_ptr())
+            : nullptr,
+        fc1_expert_weights.const_data_ptr(), nullptr, activation_type,
+        fc2_expert_weights.const_data_ptr(), nullptr, quant_params, num_rows, hidden_size,
+        inter_size, num_experts_total, static_cast<int>(experts_per_token),
+        static_cast<char*>(workspace_info.workspace), output.data_ptr(),
+        static_cast<int*>(workspace_info.src_to_dest_map), parallelism_config, false, lora_params,
+        mUseFp8BlockScaling, min_latency_mode, min_latency_params, stream);
+
+    return output;
+  }
+
+  std::tuple<torch::Tensor, torch::Tensor, torch::Tensor, torch::Tensor> runMoeMinLantency(
+      torch::Tensor const& input, torch::Tensor const& token_selected_experts,
+      torch::optional<torch::Tensor> token_final_scales, torch::Tensor const& fc1_expert_weights,
+      torch::Tensor const& fc2_expert_weights,
+      torch::optional<c10::ArrayRef<torch::Tensor>> quant_scales,
+      torch::optional<torch::Tensor> input_sf, int64_t const tp_size, int64_t const tp_rank,
+      int64_t const ep_size, int64_t const ep_rank, int64_t const cluster_size,
+      int64_t const cluster_rank, bool min_latency_mode,
+      torch::optional<c10::ArrayRef<int64_t>> profile_ids) {
+    std::lock_guard<std::mutex> lock(mMutex);
+
+    // Free the profile workspace to save memory
+    freeProfileWorkspace();
+
+    CHECK_INPUT_TYPE(input, mActivationDtype)
+    CHECK_INPUT_TYPE(token_selected_experts, at::ScalarType::Int)
+    if (token_final_scales) {
+      CHECK_INPUT_TYPE(token_final_scales.value(), at::ScalarType::Float)
+    }
+    CHECK_INPUT_TYPE(fc1_expert_weights, mWeightDtype)
+    CHECK_INPUT_TYPE(fc2_expert_weights, mWeightDtype)
+
+    TORCH_CHECK(input.dim() == 2, "input must be 2D.");
+    TORCH_CHECK(token_selected_experts.dim() == 2, "token_selected_experts must be 2D.");
+
+    TORCH_CHECK(fc1_expert_weights.dim() == 3, "fc1_expert_weights must be 3D.");
+    TORCH_CHECK(fc2_expert_weights.dim() == 3, "fc2_expert_weights must be 3D.");
+    TORCH_CHECK(input.sizes()[0] == token_selected_experts.sizes()[0],
+                "input and token_selected_experts must have the same num tokens.");
+    if (token_final_scales) {
+      TORCH_CHECK(token_final_scales.value().dim() == 2,
+                  "token_selected_experts_probs must be 2D.");
+      TORCH_CHECK(input.sizes()[0] == token_final_scales.value().sizes()[0],
+                  "input and token_selected_experts_probs must have the same num tokens.");
+      TORCH_CHECK(token_selected_experts.sizes()[1] == token_final_scales.value().sizes()[1],
+                  "token_selected_experts and token_final_scales must have the same number of "
+                  "experts per token.");
+    }
+    TORCH_CHECK(fc1_expert_weights.sizes()[0] == fc2_expert_weights.sizes()[0],
+                "fc1_expert_weights and fc2_expert_weights must have the same number of experts.");
+    TORCH_CHECK(
+        fc1_expert_weights.sizes()[1] == fc2_expert_weights.sizes()[2] * mInnerDimMultiplier * 2,
+        "fc1_expert_weights inter size must be 2 times fc2_expert_weights inter size.");
+
+    int experts_per_token = token_selected_experts.sizes()[1];
+    int64_t num_rows = input.sizes()[0];
+    int64_t hidden_size = fc2_expert_weights.sizes()[1];
+    int64_t inter_size = fc2_expert_weights.sizes()[2] * mInnerDimMultiplier;
+    int const num_experts_on_rank = fc2_expert_weights.sizes()[0];
+    auto const num_experts_total = static_cast<int>(num_experts_on_rank * ep_size);
+    auto parallelism_config = kernels::MOEParallelismConfig(tp_size, tp_rank, ep_size, ep_rank,
+                                                            cluster_size, cluster_rank);
+    auto activation_type = tensorrt_llm::ActivationType::Swiglu;
+
+    setRunnerProfiles(profile_ids);
+
+    auto stream = at::cuda::getCurrentCUDAStream(input.get_device());
+
+    std::vector<int64_t> output_shape = {num_rows * num_experts_on_rank, hidden_size};
+    auto output = torch::empty(output_shape, input.options().dtype(mOutputDtype));
+
+    auto num_active_experts_per_node =
+        torch::empty({1}, input.options().dtype(at::ScalarType::Int));
+    auto experts_to_token_score =
+        torch::empty({num_experts_on_rank, num_rows}, input.options().dtype(at::ScalarType::Float));
+    auto active_expert_global_ids =
+        torch::empty({num_experts_on_rank}, input.options().dtype(at::ScalarType::Int));
+
+    kernels::MoeMinLatencyParams min_latency_params{};
+    min_latency_params.num_active_experts_per_node =
+        static_cast<int*>(num_active_experts_per_node.data_ptr());
+    min_latency_params.experts_to_token_score =
+        static_cast<float*>(experts_to_token_score.data_ptr());
+    min_latency_params.active_expert_global_ids =
+        static_cast<int*>(active_expert_global_ids.data_ptr());
+
+    WorkspaceInfo workspace_info = getWorkspaceInfo(
+        num_rows, hidden_size, inter_size, num_experts_total, static_cast<int>(experts_per_token),
+        activation_type, parallelism_config, min_latency_mode);
+
+    auto const quant_params =
+        getQuantParams(num_experts_on_rank, hidden_size, inter_size, quant_scales);
+
+    // TODO: support lora in the future
+    kernels::LoraParams lora_params{};
+    mKernelRunner->runMoe(
+        input.const_data_ptr(), input_sf.has_value() ? input_sf.value().const_data_ptr() : nullptr,
+        reinterpret_cast<int const*>(token_selected_experts.const_data_ptr()),
+        token_final_scales.has_value()
+            ? reinterpret_cast<float const*>(token_final_scales.value().const_data_ptr())
+            : nullptr,
+        fc1_expert_weights.const_data_ptr(), nullptr, activation_type,
+        fc2_expert_weights.const_data_ptr(), nullptr, quant_params, num_rows, hidden_size,
+        inter_size, num_experts_total, static_cast<int>(experts_per_token),
+        static_cast<char*>(workspace_info.workspace), output.data_ptr(),
+        static_cast<int*>(workspace_info.src_to_dest_map), parallelism_config, false, lora_params,
+        mUseFp8BlockScaling, min_latency_mode, min_latency_params, stream);
+
+    return std::make_tuple(output, num_active_experts_per_node, experts_to_token_score,
+                           active_expert_global_ids);
+  }
+
+  int64_t getTacticNum() {
+    std::lock_guard<std::mutex> lock(mMutex);
+    return mAllProfiles.size();
+  }
+
+  void runGemmProfile(torch::Tensor const& input, torch::Tensor const& fc1_expert_weights,
+                      torch::Tensor const& fc2_expert_weights, int64_t const top_k,
+                      int64_t const tp_size, int64_t const tp_rank, int64_t const ep_size,
+                      int64_t const ep_rank, int64_t const cluster_size, int64_t const cluster_rank,
+                      bool const min_latency_mode, int64_t const gemm_idx, int64_t const profile_id,
+                      bool const do_preparation) {
+    std::lock_guard<std::mutex> lock(mMutex);
+
+    // TODO: support profiling under fp8 block scaling in the future
+    if (mUseFp8BlockScaling) {
+      return;
+    }
+
+    int64_t const num_rows = input.sizes()[0];
+    int64_t const hidden_size = fc2_expert_weights.sizes()[1];
+    int64_t const inter_size = fc2_expert_weights.sizes()[2] * mInnerDimMultiplier;
+    int64_t const group_size = isInt4Quant() ? 128 : -1;
+    int const num_experts = static_cast<int>(fc2_expert_weights.sizes()[0] * ep_size);
+
+    // Get specific profile configs according to the profile_id.
+    // Fallback tactic is set to be 0
+    // TODO: use the best tactic id found offline for a better default inference perf
+    auto const& profile = profile_id == -1 ? mAllProfiles.front() : mAllProfiles[profile_id];
+
+    auto stream = at::cuda::getCurrentCUDAStream(input.get_device());
+
+    auto const* expert_weights_ptr =
+        (gemm_idx == 1) ? fc1_expert_weights.const_data_ptr() : fc2_expert_weights.const_data_ptr();
+
+    // Preparation phase, only enabled during autotuning warmup phase.
+    if (do_preparation) {
+      // Set profiled gemm idx
+      mProfiler->mGemmToProfile = (gemm_idx == 1) ? profiler_backend::GemmToProfile::GEMM_1
+                                                  : profiler_backend::GemmToProfile::GEMM_2;
+
+      // mProfiler init
+      auto parallelism_config = kernels::MOEParallelismConfig(
+          static_cast<int>(tp_size), static_cast<int>(tp_rank), static_cast<int>(ep_size),
+          static_cast<int>(ep_rank), static_cast<int>(cluster_size),
+          static_cast<int>(cluster_rank));
+
+      bool const USE_BIAS = false;
+      bool const USE_LORA = false;
+      auto activation_dtype =
+          mUseW4A8GroupScaling ? at::ScalarType::Float8_e4m3fn : mActivationDtype;
+      activation_dtype = isNvfp4Quant() ? at::ScalarType::Long : activation_dtype;
+      mProfiler->init(*mKernelRunner.get(), mProfiler->mGemmToProfile,
+                      tensorrt_llm::runtime::TorchUtils::dataType(activation_dtype),
+                      tensorrt_llm::runtime::TorchUtils::dataType(mWeightDtype),
+                      tensorrt_llm::runtime::TorchUtils::dataType(mOutputDtype), num_experts,
+                      static_cast<int>(top_k), hidden_size, inter_size, group_size,
+                      tensorrt_llm::ActivationType::Swiglu, USE_BIAS, USE_LORA, min_latency_mode,
+                      /*need_weights*/ false, parallelism_config);
+
+      freeProfileWorkspace();
+      size_t profile_workspace_size = mProfiler->getWorkspaceSize(num_rows);
+      auto const cu_malloc_status = cudaMalloc(&mProfileWorkspace, profile_workspace_size);
+      TORCH_CHECK(cu_malloc_status == cudaSuccess,
+                  "Can't allocate profile workspace for MoE GEMM profile.");
+
+      mProfiler->prepare(num_rows, mProfileWorkspace, expert_weights_ptr, stream);
+    }
+
+    // Profile specific tactic. Assuming at least one preparation phase has been executed already.
+    mProfiler->runProfiler(num_rows, profile, mProfileWorkspace, expert_weights_ptr, stream);
+  }
