+  WorkspaceInfo getWorkspaceInfo(int64_t const num_rows, int64_t const hidden_size,
+                                 int64_t const inter_size, int num_experts, int experts_per_token,
+                                 tensorrt_llm::ActivationType activation_type,
+                                 kernels::MOEParallelismConfig const& parallelismConfig,
+                                 bool min_latency_mode) {
+    size_t moe_workspace_size = mKernelRunner->getWorkspaceSize(
+        num_rows, hidden_size, inter_size, num_experts, experts_per_token, activation_type,
+        parallelismConfig, /* use_lora */ false, mUseFp8BlockScaling, min_latency_mode,
+        mUseW4A8GroupScaling);
+    size_t src_to_dest_map_size = experts_per_token * num_rows * sizeof(int);
+
+    std::vector<size_t> workspaces{moe_workspace_size, src_to_dest_map_size};
+
+    size_t total_workspace_size =
+        common::calculateTotalWorkspaceSize(workspaces.data(), workspaces.size());
+    auto workspace =
+        torch::empty({static_cast<long>(total_workspace_size)},
+                     torch::dtype(torch::kInt8).device(torch::kCUDA).requires_grad(false));
+
+    WorkspaceInfo info{};
+    info.workspace = workspace.data_ptr();
+    info.src_to_dest_map =
+        common::nextWorkspacePtr(static_cast<int8_t*>(workspace.data_ptr()), moe_workspace_size);
+
+    return info;
+  }
