+  kernels::QuantParams getQuantParams(
+      int64_t const num_experts_on_rank, int64_t const hidden_size, int64_t const inter_size,
+      std::optional<c10::ArrayRef<at::Tensor>> const& quant_scales) const {
+    if (isFp8Quant()) {
+      TORCH_CHECK(quant_scales.has_value(), "Expecting quant scales for fp8 quantization");
+      TORCH_CHECK(quant_scales.value().size() == 4,
+                  "Expecting 4 quant scales for fp8 quantization");
+
+      auto const fc1_dequant = quant_scales.value()[0];
+      auto const fc2_quant = quant_scales.value()[1];
+      auto const fc2_dequant = quant_scales.value()[2];
+      auto const fc1_input_dequant = quant_scales.value()[3];
+
+      CHECK_INPUT_TYPE(fc1_dequant, c10::ScalarType::Float);
+      CHECK_INPUT_TYPE(fc2_quant, c10::ScalarType::Float);
+      CHECK_INPUT_TYPE(fc2_dequant, c10::ScalarType::Float);
+      CHECK_INPUT_TYPE(fc1_input_dequant, c10::ScalarType::Float);
+      TORCH_CHECK(fc1_dequant.dim() == 1, "fc1 dequant must be 1D");
+      TORCH_CHECK(fc2_quant.dim() == 0, "fc2 quant must be a scalar tensor");
+      TORCH_CHECK(fc2_dequant.dim() == 1, "fc2 quant must be 1D");
+      TORCH_CHECK(fc1_input_dequant.dim() == 0, "fc1 input dequant must be a scalar tensor");
+      TORCH_CHECK(fc1_dequant.sizes()[0] == num_experts_on_rank,
+                  "fc1 dequant size must be (num_experts_on_rank,)");
+      TORCH_CHECK(fc2_dequant.sizes()[0] == num_experts_on_rank,
+                  "fc2 dequant size must be (num_experts_on_rank,)");
+
+      return kernels::QuantParams::FP8(static_cast<float const*>(fc1_dequant.data_ptr()),
+                                       static_cast<float const*>(fc2_quant.data_ptr()),
+                                       static_cast<float const*>(fc2_dequant.data_ptr()),
+                                       /* fp8 output quant scale */ nullptr,
+                                       static_cast<float const*>(fc1_input_dequant.data_ptr()));
+    } else if (isNvfp4Quant()) {
+      TORCH_CHECK(quant_scales.has_value(), "Expecting quant scales for nvfp4 quantization");
+      TORCH_CHECK(quant_scales.value().size() == 6,
+                  "Expecting 6 quant scales for nvfp4 quantization");
+
+      auto const fc1_act_global = quant_scales.value()[0];
+      auto const fc1_weight_block = quant_scales.value()[1];
+      auto const fc1_global = quant_scales.value()[2];
+      auto const fc2_act_global = quant_scales.value()[3];
+      auto const fc2_weight_block = quant_scales.value()[4];
+      auto const fc2_global = quant_scales.value()[5];
+
+      // The input for scale fc1_weight_block / fc2_weight_block is packed into INT32
+      constexpr int FP8_PER_INT32 = 4;
+      CHECK_INPUT_TYPE(fc1_act_global, c10::ScalarType::Float);
+      CHECK_INPUT_TYPE(fc1_weight_block, c10::ScalarType::Int);
+      CHECK_INPUT_TYPE(fc1_global, c10::ScalarType::Float);
+      CHECK_INPUT_TYPE(fc2_act_global, c10::ScalarType::Float);
+      CHECK_INPUT_TYPE(fc2_weight_block, c10::ScalarType::Int);
+      CHECK_INPUT_TYPE(fc2_global, c10::ScalarType::Float);
+      TORCH_CHECK(fc1_act_global.dim() == 0, "fc1 act global must be a scalar tensor");
+      TORCH_CHECK(fc1_weight_block.dim() == 3, "fc1 weight block must be #D");
+      TORCH_CHECK(fc1_global.dim() == 1, "fc1 global must be 1D");
+      TORCH_CHECK(fc2_act_global.dim() == 0, "fc2 act global must be a scalar tensor");
+      TORCH_CHECK(fc2_weight_block.dim() == 3, "fc2 weight block must be 3D");
+      TORCH_CHECK(fc2_global.dim() == 1, "fc2 global must be 1D");
+      TORCH_CHECK(
+          fc1_weight_block.sizes()[0] == num_experts_on_rank &&
+              fc1_weight_block.sizes()[1] == inter_size * 2 &&
+              fc1_weight_block.sizes()[2] * FP8_PER_INT32 *
+                      tensorrt_llm::TmaWarpSpecializedGroupedGemmInput::BlockScaleVectorSize ==
+                  hidden_size,
+          "fc1 weight block size must be (num_experts_on_rank, inter_size * 2, hidden_size // 4 // "
+          "block_scale_vector_size)");
+      TORCH_CHECK(fc1_global.sizes()[0] == num_experts_on_rank,
+                  "fc1 global size must be (num_experts_on_rank,)");
+      TORCH_CHECK(
+          fc2_weight_block.sizes()[0] == num_experts_on_rank &&
+              fc2_weight_block.sizes()[1] == hidden_size &&
+              fc2_weight_block.sizes()[2] * FP8_PER_INT32 *
+                      tensorrt_llm::TmaWarpSpecializedGroupedGemmInput::BlockScaleVectorSize ==
+                  inter_size,
+          "fc2 weight block size must be (num_experts_on_rank, hidden_size, inter_size // 4 // "
+          "block_scale_vector_size)");
+      TORCH_CHECK(fc2_global.sizes()[0] == num_experts_on_rank,
+                  "fc2 global size must be (num_experts_on_rank,)");
+
+      return kernels::QuantParams::FP4(
+          static_cast<float const*>(fc1_act_global.data_ptr()),
+          static_cast<tensorrt_llm::TmaWarpSpecializedGroupedGemmInput::ElementSF*>(
+              fc1_weight_block.data_ptr()),
+          static_cast<float const*>(fc1_global.data_ptr()),
+          static_cast<float const*>(fc2_act_global.data_ptr()),
+          static_cast<tensorrt_llm::TmaWarpSpecializedGroupedGemmInput::ElementSF*>(
+              fc2_weight_block.data_ptr()),
+          static_cast<float const*>(fc2_global.data_ptr()));
+    } else if (mUseFp8BlockScaling) {
+      auto& fc1_scales = quant_scales.value()[0];
+      auto& fc2_scales = quant_scales.value()[1];
+      return kernels::QuantParams::FP8BlockScaling(
+          static_cast<float const*>(fc1_scales.data_ptr()),
+          static_cast<float const*>(fc2_scales.data_ptr()));
+    } else if (isInt4Quant()) {
+      TORCH_CHECK(quant_scales.has_value(), "Expecting quant scales for INT4 quantization");
+      TORCH_CHECK(quant_scales.value().size() == 8,
+                  "Expecting 8 quant scales for INT4 quantization");
+      auto& fc1_weight_scales = quant_scales.value()[0];
+      auto& fc2_weight_scales = quant_scales.value()[1];
+      auto& fc1_act_scales = quant_scales.value()[2];
+      auto& fc2_act_scales = quant_scales.value()[3];
+      auto& fc1_weight_zeros = quant_scales.value()[4];
+      auto& fc2_weight_zeros = quant_scales.value()[5];
+      auto& fc1_alpha = quant_scales.value()[6];
+      auto& fc2_alpha = quant_scales.value()[7];
+      int group_size = 128;
+      return kernels::QuantParams::GroupWise(
+          group_size, static_cast<void const*>(fc1_weight_scales.data_ptr()),
+          static_cast<void const*>(fc2_weight_scales.data_ptr()),
+          static_cast<void const*>(fc1_act_scales.numel() > 0 ? fc1_act_scales.data_ptr()
+                                                              : nullptr),
+          static_cast<void const*>(fc2_act_scales.numel() > 0 ? fc2_act_scales.data_ptr()
+                                                              : nullptr),
+          static_cast<void const*>(fc1_weight_zeros.numel() > 0 ? fc1_weight_zeros.data_ptr()
+                                                                : nullptr),
+          static_cast<void const*>(fc2_weight_zeros.numel() > 0 ? fc2_weight_zeros.data_ptr()
+                                                                : nullptr),
+          static_cast<float const*>(fc1_alpha.numel() > 0 ? fc1_alpha.data_ptr() : nullptr),
+          static_cast<float const*>(fc2_alpha.numel() > 0 ? fc2_alpha.data_ptr() : nullptr));
+    } else {
+      return kernels::QuantParams{};
+    }
+  }
+
+  bool isFp8Quant() const {
+    return !mUseFp8BlockScaling && mActivationDtype == c10::ScalarType::Float8_e4m3fn &&
+           mWeightDtype == c10::ScalarType::Float8_e4m3fn;
+  }
+
+  bool isNvfp4Quant() const { return mWeightDtype == c10::ScalarType::Long; }
+
+  bool isInt4Quant() const { return mWeightDtype == c10::ScalarType::QUInt4x2; }
+
+  bool isW4AFp8Quant() const {
+    return mActivationDtype == c10::ScalarType::Float8_e4m3fn && isInt4Quant();
+  }
+};
