+std::string trim(std::string const& str) {
+  size_t start = str.find_first_not_of(" \t\n\r");
+  size_t end = str.find_last_not_of(" \t\n\r");
+  return (start == std::string::npos || end == std::string::npos)
+             ? ""
+             : str.substr(start, end - start + 1);
+}
