+template <typename T>
+__global__ void check_range(T const* buffer, size_t size, T min, T max, bool* d_within_range) {
+  for (size_t i = blockIdx.x * blockDim.x + threadIdx.x; i < size; i += blockDim.x * gridDim.x) {
+    const T val = buffer[i];
+    if (val < min || val > max) {
+      *d_within_range = false;
+    }
+  }
+}
+
+template <typename T>
+bool invokeCheckRange(T const* buffer, const size_t size, T min, T max, bool* d_within_range,
+                      cudaStream_t stream) {
+  cudaMemsetAsync(d_within_range, true, sizeof(bool), stream);
+
+  dim3 block(256);
+  dim3 grid((size + 255) / 256);
+  check_range<T><<<grid, block, 0, stream>>>(buffer, size, min, max, d_within_range);
+
+  bool result;
+  cudaD2Hcpy(&result, d_within_range, 1);
+  return result;
+}
+
+template bool invokeCheckRange<int>(int const* buffer, const size_t size, int min, int max,
+                                    bool* d_within_range, cudaStream_t stream);
