+template <typename T>
+void checkEx(T ptr, std::initializer_list<T> const& validReturns, char const* const func,
+             char const* const file, int const line) {
+  if (std::all_of(std::begin(validReturns), std::end(validReturns),
+                  [&ptr](T const& t) { return t != ptr; })) {
+    throw TllmException(
+        file, line,
+        fmtstr("[TensorRT-LLM][ERROR] CUDA runtime error in %s: %s", func, _cudaGetErrorEnum(ptr))
+            .c_str());
