+inline __device__ uint32_t elect_one_sync() {
+  uint32_t pred = 0;
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900) && (__CUDACC_VER_MAJOR__ >= 12))
+#if (defined(__CUDA_ARCH_FEAT_SM90_ALL))
+  uint32_t laneid = 0;
+  asm volatile(
+      "\n\
+    {\n\
+        .reg .b32 %rx;\n\
+        .reg .pred %px;\n\
+        elect.sync %rx|%px, %2;\n\
+        @%px mov.s32 %1, 1;\n\
+        mov.s32 %0, %rx;\n\
+    }\n\
+  "
+      : "+r"(laneid), "+r"(pred)
+      : "r"(0xFFFFFFFF));
+#endif
+#endif
+  return pred;
+}
