+__forceinline__ __device__ void arrive_DSMEM_barrier(uint64_t* p_barrier, uint32_t ctaid) {
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800))
+  uint64_t* p_barrier_remote = get_DSMEM_ptr(p_barrier, ctaid);
+  asm volatile("{mbarrier.arrive.b64   _, [%0];\n\t}" : : "l"(p_barrier_remote));
+#endif
+}
+
+__forceinline__ __device__ void arrive_DSMEM_barrier_and_set_tx_cnt(uint64_t* p_barrier,
+                                                                    uint32_t ctaid,
+                                                                    uint32_t expected_copy_bytes) {
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800))
+  uint32_t p_bar =
+      static_cast<uint32_t>(reinterpret_cast<uintptr_t>(get_DSMEM_ptr(p_barrier, ctaid)));
+  asm volatile("{mbarrier.arrive.expect_tx.b64 _, [%0], %1; \n\t}" ::"r"(p_bar),
+               "r"(expected_copy_bytes));
+#endif
+}
