+template <bool barSetTxCnt = true>
+__forceinline__ __device__ void stas(uint32_t* p_data, uint64_t* p_barrier, uint32_t ctaid,
+                                     uint32_t const& wrdat) {
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800))
+  if (barSetTxCnt) arrive_DSMEM_barrier_and_set_tx_cnt(p_barrier, ctaid, sizeof(uint32_t));
+  uint32_t buffer_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_data));
+  uint32_t barrier_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_barrier));
+
+  uint32_t buffer_ptr_, barrier_ptr_;
+  asm volatile(
+      "{\n\t"
+      "setctarank.shared.u32 %0, %2, %4;\n\t"
+      "setctarank.shared.u32 %1, %3, %4;\n\t"
+      "}"
+      : "=r"(buffer_ptr_), "=r"(barrier_ptr_)
+      : "r"(buffer_ptr), "r"(barrier_ptr), "r"(ctaid));
+  issue_stas(buffer_ptr_, barrier_ptr_, wrdat);
+#endif
+}
+
+template <bool barSetTxCnt = true>
+__forceinline__ __device__ void stas(uint64_t* p_data, uint64_t* p_barrier, uint32_t ctaid,
+                                     uint64_t const& wrdat) {
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800))
+  if (barSetTxCnt) arrive_DSMEM_barrier_and_set_tx_cnt(p_barrier, ctaid, sizeof(uint64_t));
+  uint32_t buffer_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_data));
+  uint32_t barrier_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_barrier));
+
+  uint32_t buffer_ptr_, barrier_ptr_;
+  asm volatile(
+      "{\n\t"
+      "setctarank.shared.u32 %0, %2, %4;\n\t"
+      "setctarank.shared.u32 %1, %3, %4;\n\t"
+      "}"
+      : "=r"(buffer_ptr_), "=r"(barrier_ptr_)
+      : "r"(buffer_ptr), "r"(barrier_ptr), "r"(ctaid));
+  issue_stas(buffer_ptr_, barrier_ptr_, wrdat);
+#endif
+}
+
+template <bool barSetTxCnt = true>
+__forceinline__ __device__ void stas(uint64_t* p_data, uint64_t* p_barrier, uint32_t ctaid,
+                                     uint32_t const wrdat0, uint32_t const wrdat1,
+                                     uint32_t const wrdat2, uint32_t const wrdat3) {
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800))
+  if (barSetTxCnt) arrive_DSMEM_barrier_and_set_tx_cnt(p_barrier, ctaid, 4 * sizeof(uint32_t));
+  uint32_t buffer_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_data));
+  uint32_t barrier_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_barrier));
+
+  uint32_t buffer_ptr_, barrier_ptr_;
+  asm volatile(
+      "{\n\t"
+      "setctarank.shared.u32 %0, %2, %4;\n\t"
+      "setctarank.shared.u32 %1, %3, %4;\n\t"
+      "}"
+      : "=r"(buffer_ptr_), "=r"(barrier_ptr_)
+      : "r"(buffer_ptr), "r"(barrier_ptr), "r"(ctaid));
+  issue_stas(buffer_ptr_, barrier_ptr_, wrdat0, wrdat1, wrdat2, wrdat3);
+#endif
+}
+
+template <bool barSetTxCnt = true, bool assumeAligned = true, typename T = void>
+__forceinline__ __device__ void stas(T* p_data, uint64_t* p_barrier, uint32_t ctaid,
+                                     T const& wrdat) {
+#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800))
+  static_assert(sizeof(T) % 4 == 0);
+  if (barSetTxCnt) arrive_DSMEM_barrier_and_set_tx_cnt(p_barrier, ctaid, sizeof(T));
+
+  uint32_t buffer_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_data));
+  uint32_t barrier_ptr = static_cast<uint32_t>(reinterpret_cast<uintptr_t>(p_barrier));
+
+  uint32_t buffer_ptr_, barrier_ptr_;
+  asm volatile(
+      "{\n\t"
+      "setctarank.shared.u32 %0, %2, %4;\n\t"
+      "setctarank.shared.u32 %1, %3, %4;\n\t"
+      "}"
+      : "=r"(buffer_ptr_), "=r"(barrier_ptr_)
+      : "r"(buffer_ptr), "r"(barrier_ptr), "r"(ctaid));
+
+  uint32_t const* p_wrdat_b32 = reinterpret_cast<uint32_t const*>(&wrdat);
+
+  for (uint32_t offset = 0; offset < sizeof(T);) {
+    if constexpr (assumeAligned) {
+      if (offset + 16 <= sizeof(T)) {
+        // Use write_async_v4_b32
+        issue_stas(buffer_ptr_ + offset, barrier_ptr_, p_wrdat_b32[offset / 4],
+                   p_wrdat_b32[offset / 4 + 1], p_wrdat_b32[offset / 4 + 2],
+                   p_wrdat_b32[offset / 4 + 3]);
+        offset += 16;
+      } else if (offset + 8 <= sizeof(T) && (buffer_ptr + offset) % 8 == 0) {
+        // Use write_async_v2_b32
+        issue_stas(buffer_ptr + offset, barrier_ptr_, p_wrdat_b32[offset / 4],
+                   p_wrdat_b32[offset / 4 + 1]);
+        offset += 8;
+      } else {
+        issue_stas(buffer_ptr + offset, barrier_ptr_, p_wrdat_b32[offset / 4]);
+        offset += 4;
+      }
+    } else {
+      issue_stas(buffer_ptr + offset, barrier_ptr_, p_wrdat_b32[offset / 4]);
+      offset += 4;
+    }
+  }
+#endif
+}
