+#define TLLM_CUDA_CHECK(stat)                                       \
+  do {                                                              \
+    tensorrt_llm::common::check((stat), #stat, __FILE__, __LINE__); \
+  } while (0)
+
+// We use singleton memory pool and the order of destructors depends on the compiler implementation.
+// We find that the cudaFree/cudaFreeHost is called after cudaruntime destruction on Windows. There
+// will be an cudaErrorCudartUnloading error.  However, it is safe to ignore this error because the
+// cuda runtime is already exited, we are no more worried about the memory leaks.
+#define TLLM_CUDA_CHECK_FREE_RESOURCE(stat)                                               \
+  do {                                                                                    \
+    tensorrt_llm::common::checkEx((stat), {cudaSuccess, cudaErrorCudartUnloading}, #stat, \
+                                  __FILE__, __LINE__);                                    \
+  } while (0)

