+constexpr static size_t getDTypeSize(nvinfer1::DataType type) {
+  switch (type) {
+    case nvinfer1::DataType::kINT64:
+      return 8;
+    case nvinfer1::DataType::kINT32:
+      [[fallthrough]];
+    case nvinfer1::DataType::kFLOAT:
+      return 4;
+    case nvinfer1::DataType::kBF16:
+      [[fallthrough]];
+    case nvinfer1::DataType::kHALF:
+      return 2;
+    case nvinfer1::DataType::kBOOL:
+      [[fallthrough]];
+    case nvinfer1::DataType::kUINT8:
+      [[fallthrough]];
+    case nvinfer1::DataType::kINT8:
+      [[fallthrough]];
+    case nvinfer1::DataType::kFP8:
+      return 1;
+    case nvinfer1::DataType::kINT4:
+      TLLM_THROW("Cannot determine size of INT4 data type");
+    case nvinfer1::DataType::kFP4:
+      TLLM_THROW("Cannot determine size of FP4 data type");
+    default:
+      TLLM_THROW("Unknown dtype %d", static_cast<int>(type));
+  }
+  return 0;
+}
+
+constexpr static size_t getDTypeSizeInBits(nvinfer1::DataType type) {
+  switch (type) {
+    case nvinfer1::DataType::kINT64:
+      return 64;
+    case nvinfer1::DataType::kINT32:
+      [[fallthrough]];
+    case nvinfer1::DataType::kFLOAT:
+      return 32;
+    case nvinfer1::DataType::kBF16:
+      [[fallthrough]];
+    case nvinfer1::DataType::kHALF:
+      return 16;
+    case nvinfer1::DataType::kBOOL:
+      [[fallthrough]];
+    case nvinfer1::DataType::kUINT8:
+      [[fallthrough]];
+    case nvinfer1::DataType::kINT8:
+      [[fallthrough]];
+    case nvinfer1::DataType::kFP8:
+      return 8;
+    case nvinfer1::DataType::kINT4:
+      [[fallthrough]];
+    case nvinfer1::DataType::kFP4:
+      return 4;
+    default:
+      TLLM_THROW("Unknown dtype %d", static_cast<int>(type));
+  }
+  return 0;
+}
