+inline void toLower(std::string& s) {
+  for (char& c : s) {
+    c = std::tolower(static_cast<unsigned char>(c));
+  }
+}
+
+/// @brief Convert string to upper-case (inplace)
+inline void toUpper(std::string& s) {
+  for (char& c : s) {
+    c = std::toupper(static_cast<unsigned char>(c));
+  }
+}

