+#if defined(__CUDA_ARCH__) && __CUDA_ARCH__ < 800
+  float fxl, fxh, fyl, fyh, fzl, fzh;
+  fxl = __low2float(x);
+  fxh = __high2float(x);
+  fyl = __low2float(y);
+  fyh = __high2float(y);
+  fzl = __low2float(z);
+  fzh = __high2float(z);
+  return __floats2bfloat162_rn(fxl * fyl + fzl, fxh * fyh + fzh);
