+#if defined(__CUDA_ARCH__) && __CUDA_ARCH__ < 800
+  float fal, fah, fbl, fbh, fcl, fch, fdl, fdh;
+  fal = __low2float(a);
+  fah = __high2float(a);
+  fbl = __low2float(b);
