+// The following functions implement conversion of multi-dimensional indices to an index in a flat
+// array. The shape of the Tensor dimensions is passed as one array (`dims`), the indices are given
+// as individual arguments. For examples on how to use these functions, see their tests
+// `test_memory_utils.cu`. All of these functions can be evaluated at compile time by recursive
+// template expansion.
+
+template <typename TDim, typename T, typename TIndex>
+__inline__ __host__ __device__
+    std::enable_if_t<std::is_pointer<TDim>::value, T> constexpr flat_index(T const& acc, TDim dims,
+                                                                           TIndex const& index) {
+  assert(index < dims[0]);
+  return acc * dims[0] + index;
+}
+
+template <typename TDim, typename T, typename TIndex, typename... TIndices>
+__inline__ __host__ __device__
+    std::enable_if_t<std::is_pointer<TDim>::value, T> constexpr flat_index(T const& acc, TDim dims,
+                                                                           TIndex const& index,
+                                                                           TIndices... indices) {
+  assert(index < dims[0]);
+  return flat_index(acc * dims[0] + index, dims + 1, indices...);
+}
+
+template <typename TDim, typename T>
+__inline__ __host__ __device__
+    std::enable_if_t<std::is_pointer<TDim>::value, T> constexpr flat_index(
+        [[maybe_unused]] TDim dims, T const& index) {
+  assert(index < dims[0]);
+  return index;
+}
+
+template <typename TDim, typename TIndex, typename... TIndices>
+__inline__ __host__ __device__ std::enable_if_t<
+    std::is_pointer<TDim>::value,
+    typename std::remove_pointer<TDim>::type> constexpr flat_index(TDim dims, TIndex const& index,
+                                                                   TIndices... indices) {
+  assert(index < dims[0]);
+  return flat_index(static_cast<typename std::remove_pointer<TDim>::type>(index), dims + 1,
+                    indices...);
+}
+
+template <unsigned skip = 0, typename T, std::size_t N, typename TIndex, typename... TIndices>
+__inline__ __host__ __device__ T constexpr flat_index(std::array<T, N> const& dims,
+                                                      TIndex const& index, TIndices... indices) {
+  static_assert(skip < N);
+  static_assert(sizeof...(TIndices) < N - skip, "Number of indices exceeds number of dimensions");
+  return flat_index(&dims[skip], index, indices...);
+}
+
+template <unsigned skip = 0, typename T, typename TIndex, std::size_t N, typename... TIndices>
+__inline__ __host__ __device__ T constexpr flat_index(T const& acc, std::array<T, N> const& dims,
+                                                      TIndex const& index, TIndices... indices) {
+  static_assert(skip < N);
+  static_assert(sizeof...(TIndices) < N - skip, "Number of indices exceeds number of dimensions");
+  return flat_index(acc, &dims[skip], index, indices...);
+}
+
+template <unsigned skip = 0, typename T, typename TIndex, std::size_t N, typename... TIndices>
+__inline__ __host__ __device__ T constexpr flat_index(T const (&dims)[N], TIndex const& index,
+                                                      TIndices... indices) {
+  static_assert(skip < N);
+  static_assert(sizeof...(TIndices) < N - skip, "Number of indices exceeds number of dimensions");
+  return flat_index(static_cast<T const*>(dims) + skip, index, indices...);
+}
+
+template <unsigned skip = 0, typename T, typename TIndex, std::size_t N, typename... TIndices>
+__inline__ __host__ __device__ T constexpr flat_index(T const& acc, T const (&dims)[N],
+                                                      TIndex const& index, TIndices... indices) {
+  static_assert(skip < N);
+  static_assert(sizeof...(TIndices) < N - skip, "Number of indices exceeds number of dimensions");
+  return flat_index(acc, static_cast<T const*>(dims) + skip, index, indices...);
+}
