+////////////////////////////////////////////////////////////////////////////////////////////////////
+
+// These are simpler functions for multi-dimensional index conversion. Indices and dimensions are
+// passed as individual arguments. These functions are more suitable for usage inside kernels than
+// the corresponding flat_index functions which require arrays as arguments. Usage examples can be
+// found in `test_memory_utils.cu`. The functions can be evaluated at compile time.
+
+template <typename T, typename TIndex>
+__inline__ __host__ __device__ T constexpr flat_index2(TIndex const& index_0, TIndex const& index_1,
+                                                       T const& dim_1) {
+  assert(index_1 < dim_1);
+  return index_0 * dim_1 + index_1;
+}
+
+template <typename T, typename TIndex>
+__inline__ __host__ __device__ T constexpr flat_index3(TIndex const& index_0, TIndex const& index_1,
+                                                       TIndex const& index_2, T const& dim_1,
+                                                       T const& dim_2) {
+  assert(index_2 < dim_2);
+  return flat_index2(index_0, index_1, dim_1) * dim_2 + index_2;
+}
+
+template <typename T, typename TIndex>
+__inline__ __host__ __device__ T constexpr flat_index4(TIndex const& index_0, TIndex const& index_1,
+                                                       TIndex const& index_2, TIndex const& index_3,
+                                                       T const& dim_1, T const& dim_2,
+                                                       T const& dim_3) {
+  assert(index_3 < dim_3);
+  return flat_index3(index_0, index_1, index_2, dim_1, dim_2) * dim_3 + index_3;
+}
+
+template <typename T, typename TIndex>
+__inline__ __host__ __device__ T constexpr flat_index5(TIndex const& index_0, TIndex const& index_1,
+                                                       TIndex const& index_2, TIndex const& index_3,
+                                                       TIndex const& index_4, T const& dim_1,
+                                                       T const& dim_2, T const& dim_3,
+                                                       T const& dim_4) {
+  assert(index_4 < dim_4);
+  return flat_index4(index_0, index_1, index_2, index_3, dim_1, dim_2, dim_3) * dim_4 + index_4;
+}
+
+template <typename T, typename TIndex>
+__inline__ __host__ __device__ T constexpr flat_index_strided3(TIndex const& index_0,
+                                                               TIndex const& index_1,
+                                                               TIndex const& index_2,
+                                                               T const& stride_1,
+                                                               T const& stride_2) {
+  assert(index_1 < stride_1 / stride_2);
+  assert(index_2 < stride_2);
+  return index_0 * stride_1 + index_1 * stride_2 + index_2;
+}
+
+template <typename T, typename TIndex>
+__inline__ __host__ __device__ T constexpr flat_index_strided4(
+    TIndex const& index_0, TIndex const& index_1, TIndex const& index_2, TIndex const& index_3,
+    T const& stride_1, T const& stride_2, T const& stride_3) {
+  assert(index_1 < stride_1 / stride_2);
+  assert(index_2 < stride_2 / stride_3);
+  assert(index_3 < stride_3);
+  return index_0 * stride_1 + index_1 * stride_2 + index_2 * stride_3 + index_3;
+}
