+template <int NUM>
+__inline__ __device__ void cgBlockReduceSumElements(float* element_list,
+                                                    float* cgBlockReduceSumElements_shm) {
+  cg::thread_block cta = cg::this_thread_block();
+  cg::thread_block_tile<32> tile = cg::tiled_partition<32>(cta);
