+  int const tid = cta.thread_rank();
+  int const blockz = blockDim.x;
+  for (int i = 0; i < NUM; i++) {
+#if ((__CUDACC_VER_MAJOR__ > 11) || (__CUDACC_VER_MAJOR__ == 11 && __CUDACC_VER_MINOR__ >= 0))
