+    RTensor tC_rAux;      // (CPY,CPY_M,CPY_N)
+    STensorR2S tRS_sAux;  // (R2S,R2S_M,R2S_N,PIPE)
+    STensorS2G bSG_sAux;  // (S2G,S2G_M,S2G_N,PIPE)
