+      if (m >= size<0>(params_ptr->tile_layout.shape()) ||
+          n >= size<1>(params_ptr->tile_layout.shape())) {
+        // early exit if out of bound
+        return;
+      }
+
+      if (params_ptr->world_size == 1) {
+        return;  // single-GPU doesn't need AR
+      }
+
+      // if (issued_tma_store)
+      // {
+      //     assert(params_ptr->world_size <= warpSize);
