+    }
+  };
+
+  template <bool ReferenceSrc,  // do register tensors reference the src or dst layout of the tiled
+                                // copy
+            class... Args>
+  CUTLASS_DEVICE auto get_consumer_store_callbacks(ConsumerStoreArgs<Args...> const& args) {
+    auto [M, N, K, L] = args.problem_shape_mnkl;
+    auto [m, n, k, l] = args.tile_coord_mnkl;
+
+    auto problem_shape_mnl = make_shape(M, N, L);
+    auto tile_coord_mnl = make_coord(m, n, l);
+
+    Tensor mAux = params_ptr->tma_store_aux.get_tma_tensor(problem_shape_mnl);  // (M,N,L)
+    Tensor gAux =
+        local_tile(mAux, take<0, 2>(args.tile_shape_mnk), tile_coord_mnl);  // (CTA_M,CTA_N)
+
+    Tensor tC_gAux = sm90_partition_for_epilogue<ReferenceSrc>(  // (CPY,CPY_M,CPY_N,EPI_M,EPI_N)
+        gAux, args.epi_tile, args.tiled_copy, args.thread_idx);
+    Tensor tC_rAux = make_tensor<ElementT>(take<0, 3>(shape(tC_gAux)));  // (CPY,CPY_M,CPY_N)
+
+    Tensor sAux_epi = cute::as_position_independent_swizzle_tensor(
+        make_tensor(make_smem_ptr(smem_aux), SmemLayout{}));  // (EPI_TILE_M,EPI_TILE_N,PIPE)
+    Tensor gAux_epi = flat_divide(gAux, args.epi_tile);       // (EPI_TILE_M,EPI_TILE_N,EPI_M,EPI_N)
+
+    auto tiled_r2s = conditional_return<ReferenceSrc>(
+        make_tiled_copy_S(Copy_Atom<CopyOpR2S, ElementT>{}, args.tiled_copy),
+        make_tiled_copy_D(Copy_Atom<CopyOpR2S, ElementT>{}, args.tiled_copy));
+    auto tRS_sAux =
+        tiled_r2s.get_slice(args.thread_idx).partition_D(sAux_epi);  // (R2S,R2S_M,R2S_N,PIPE)
+
+    ThrCopy thrblk_s2g = params_ptr->tma_store_aux.get_slice(_0{});
+    Tensor bSG_sAux = thrblk_s2g.partition_S(sAux_epi);  // (TMA,TMA_M,TMA_N,PIPE)
+    Tensor bSG_gAux = thrblk_s2g.partition_D(gAux_epi);  // (TMA,TMA_M,TMA_N,EPI_M,EPI_N)
+
+    constexpr int NumThreads = size(decltype(args.tiled_mma){});  // sync threads
+
+    return ConsumerStoreCallbacks<NumThreads, decltype(tC_rAux), decltype(tiled_r2s),
+                                  decltype(tRS_sAux), decltype(bSG_sAux), decltype(bSG_gAux),
+                                  decltype(problem_shape_mnl), decltype(tile_coord_mnl)>(
+        cute::move(tC_rAux), tiled_r2s, cute::move(tRS_sAux), cute::move(bSG_sAux),
+        cute::move(bSG_gAux), params_ptr, problem_shape_mnl, tile_coord_mnl, args.thread_idx);
+  }
+};
+
+// D = AllReduce(activation(alpha * acc + beta * C))
+template <bool IsOneShot_, class SystemBarrier_, class GmemLayoutTagAux_, class ElementAux_,
+          class ElementCompute_, class ElementSource_ = ElementAux_,
+          class ElementScalar_ = ElementCompute_,
+          FloatRoundStyle RoundStyle_ = FloatRoundStyle::round_to_nearest>
+struct Sm90LinCombAuxAllReduce
+    : LinearCombination<ElementAux_, ElementCompute_, ElementSource_, ElementScalar_, RoundStyle_> {
+  using ElementAux = ElementAux_;
+  using GmemLayoutTagAux = GmemLayoutTagAux_;
+  static constexpr int AlignmentAux = 128 / cute::sizeof_bits_v<ElementAux_>;
+  static constexpr bool IsAuxOutSupported = true;
+};
+
+template <int StagesD, bool IsOneShot, class SystemBarrier, class GmemLayoutTagOutput,
+          class ElementOutput, class ElementCompute, class ElementSource, class ElementScalar,
+          FloatRoundStyle RoundStyle, class CtaTileShapeMNK, class EpilogueTile,
+          class SmemLayoutAtom, class CopyOpR2S>
+using Sm90LinearCombAuxAllReduce = Sm90EVT<
+    Sm90AuxAllReduce<StagesD, EpilogueTile, ElementOutput,
+                     cutlass::gemm::TagToStrideC_t<GmemLayoutTagOutput>, SmemLayoutAtom, RoundStyle,
+                     CopyOpR2S, CtaTileShapeMNK, SystemBarrier, IsOneShot>,  // Aux AR
+    Sm90LinearCombination<ElementOutput, ElementCompute, ElementSource, ElementScalar,
+                          RoundStyle>  // beta * C +
+                                       // (alpha * acc)
+    >;
+
+template <
+    // Dispatch policy arguments
+    int StagesC, int StagesD, int FragmentSize, bool ReuseSmemC, bool DelayTmaStore,
+    // Fusion Op arguments
+    bool IsOneShot, class SystemBarrier, class GmemLayoutTagD, class ElementD, class ElementCompute,
+    class ElementC, class ElementScalar, FloatRoundStyle RoundStyle,
+    // Epilogue arguments
+    class CtaTileShapeMNK, class EpilogueTile, class SmemLayoutAtom, class CopyOpR2S>
+struct FusionCallbacks<
+    epilogue::Sm90TmaWarpSpecialized<StagesC, StagesD, FragmentSize, ReuseSmemC, DelayTmaStore>,
+    Sm90LinCombAuxAllReduce<IsOneShot, SystemBarrier, GmemLayoutTagD, ElementD, ElementCompute,
+                            ElementC, ElementScalar, RoundStyle>,
+    CtaTileShapeMNK, EpilogueTile, SmemLayoutAtom, CopyOpR2S>
+    : Sm90LinearCombAuxAllReduce<StagesD, IsOneShot, SystemBarrier, GmemLayoutTagD, ElementD,
+                                 ElementCompute, ElementC, ElementScalar, RoundStyle,
+                                 CtaTileShapeMNK, EpilogueTile, SmemLayoutAtom, CopyOpR2S> {
+  using Impl =
+      Sm90LinearCombAuxAllReduce<StagesD, IsOneShot, SystemBarrier, GmemLayoutTagD, ElementD,
+                                 ElementCompute, ElementC, ElementScalar, RoundStyle,
+                                 CtaTileShapeMNK, EpilogueTile, SmemLayoutAtom, CopyOpR2S>;
+  using Operation = Sm90LinCombAuxAllReduce<IsOneShot, SystemBarrier, GmemLayoutTagD, ElementD,
+                                            ElementCompute, ElementC, ElementScalar, RoundStyle>;
+
+  struct Arguments {
+    using StrideD = cutlass::gemm::TagToStrideC_t<GmemLayoutTagD>;
+    ElementScalar alpha = ElementScalar(1);
+    ElementScalar beta = ElementScalar(0);
+    ElementScalar const* alpha_ptr = nullptr;
+    ElementScalar const* beta_ptr = nullptr;
+    ElementD* multicast_ptr_aux = nullptr;
+    ElementD* ptr_aux = nullptr;
+    StrideD dAux = {};
+    typename SystemBarrier::Params barrier_params{};
+    int rank = 0;
+    int num_ranks = 1;
+    using StrideAlpha = Stride<_0, _0, int64_t>;
+    using StrideBeta = Stride<_0, _0, int64_t>;
+    StrideAlpha dAlpha = {_0{}, _0{}, 0};
+    StrideBeta dBeta = {_0{}, _0{}, 0};
+
+    operator typename Impl::Arguments() const {
+      return {{
+                  // ternary op : beta * C + (alpha * acc)
+                  {{beta}, {beta_ptr}, {dBeta}},  // leaf args : beta
+                  {},                             // leaf args : C
+                  {
+                      // binary op : alpha * acc
+                      {{alpha}, {alpha_ptr}, {dAlpha}},  // leaf args : alpha
+                      {},                                // leaf args : acc
+                      {}                                 // binary args : multiplies
+                  },                                     // end binary op
+                  {}                                     // ternary args : multiply_add
+              },                                         // end ternary op
+              {multicast_ptr_aux, ptr_aux, dAux, barrier_params, rank, num_ranks}};
+    }
+  };
+
+  // Ctor inheritance
+  using Impl::Impl;
+};
