+class GemmARUniversal<
+    ProblemShape_, CollectiveMainloop_, CollectiveEpilogue_, CollectiveAllReduce_, TileScheduler_,
+    cute::enable_if_t<cute::is_base_of_v<KernelTmaWarpSpecialized,
+                                         typename CollectiveMainloop_::DispatchPolicy::Schedule>>> {
+ public:
+  //
+  // Type Aliases
+  //
+  using ProblemShape = ProblemShape_;
+  static_assert(cute::rank(ProblemShape{}) == 3 or cute::rank(ProblemShape{}) == 4,
+                "ProblemShape{} should be <M,N,K> or <M,N,K,L>");
+  // Mainloop derived types
