+                      Stages, TransformBAfterLDS_, QuantOp_, SharedMemoryClear,
+                      std::enable_if_t<!isFinegrained(QuantOp_)>>
+    : public DqMmaBase<Shape_, Policy_, typename IteratorScale_::Element, Stages, QuantOp_> {
+ public:
