+  //                            cutlass::arch::Sm90, EpilogueTag, true>
+  //                                           :
+  //                                           kernels::cutlass_kernels::genericMoeGemmKernelLauncherHopper<T,
+  //                                           WeightType,
+  //                                               cutlass::arch::Sm90, EpilogueTag, false>;
+  // TODO(dastokes) Re-enable bias when CUTLASS supports it
