+  m.def(
+      "fp4_quantize(Tensor input, Tensor globalScale, int sfVecSize, bool sfUseUE8M0=False, bool "
+      "swizzedLayout=True) "
+      "-> (Tensor, Tensor)",
+      &torch_ext::fp4_quantize);
+}
